// TestLibraryMapValidation checks the LibraryMap for missing ecosystems
func TestLibraryMapValidation(t *testing.T) {
	t.Logf("\n=== Library Map Ecosystem Validation ===\n")

	expectedEcosystems := map[string][]string{
		"node": {"package-lock.json", "yarn.lock", "pnpm-lock.yaml"},
		"python": {"requirements.txt", "Pipfile.lock", "poetry.lock"},
		"ruby": {"Gemfile.lock"},
		"php": {"composer.lock"},
		"java": {"pom.xml", "*.jar", "*.war"},
		"rust": {"Cargo.lock"},
		"gomod": {"go.mod", "go.sum"},
		".net": {"packages.lock.json", "packages.config"},
	}

	t.Logf("Expected Ecosystems in LibraryMap:")
	for ecosystem, files := range expectedEcosystems {
		t.Logf("\n%s:", ecosystem)
		for _, f := range files {
